#include <stdio.h>
#include <stdlib.h>

int main() {
  int* ptr = (int*)malloc(100 * sizeof(int));
  if (ptr == NULL) {
    printf("Yaddaş ayrılmadı\n");
    return 1;
  }
  ptr[0] = 42;
  printf("Dəyər: %d\n", ptr[0]);
  free(ptr); // Yaddaş azad edilir
  ptr = NULL; // Göstərici NULL-a təyin edilir
  return 0;
}
// Output:
// Dəyər: 42

